const input = $input.first().json;

function pickRaw(i) {
  if (i.content && i.content[0] && i.content[0].text) return i.content[0].text;
  if (i.text) return i.text;
  if (i.output) return i.output;
  if (i.message) return i.message;
  return JSON.stringify(i);
}

function extractJsonText(raw) {
  let t = String(raw || '').trim();
  t = t.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();
  const first = t.indexOf('{');
  const last = t.lastIndexOf('}');
  if (first !== -1 && last !== -1 && last > first) t = t.slice(first, last + 1);
  return t;
}

function repairJson(text) {
  let t = text;
  t = t.replace(/[“”]/g, '"').replace(/[‘’]/g, "'");
  t = t.replace(/,\s*([}\]])/g, '$1');
  t = t.replace(/[\u0000-\u0008\u000B\u000C\u000E-\u001F]/g, '');
  return t;
}

const raw = pickRaw(input);
const candidate = extractJsonText(raw);

let parsed;
try {
  parsed = JSON.parse(candidate);
} catch (e1) {
  try {
    parsed = JSON.parse(repairJson(candidate));
  } catch (e2) {
    throw new Error('JSON 파싱 실패: ' + e2.message + '\n---원본 일부---\n' + String(raw).slice(0, 700));
  }
}

const summaryRaw = parsed.sermon_summary || {};
const sermon_summary = {
  key_point: summaryRaw.key_point || summaryRaw.keyPoint || '',
  overview: summaryRaw.overview || '',
  sections: Array.isArray(summaryRaw.sections)
    ? summaryRaw.sections.map(function(s){ return { title: (s && s.title) || '', content: (s && s.content) || '' }; })
    : []
};

const qRoot = parsed.questions || parsed;
let sections = [];
if (Array.isArray(qRoot && qRoot.sections)) {
  sections = qRoot.sections;
} else if (Array.isArray(qRoot)) {
  sections = [{ section_title: '통합 나눔', summary_anchor: '', questions: qRoot }];
}

const normalizedSections = sections
  .map(function(sec, secIdx) {
    const title = (sec && (sec.section_title || sec.title || sec.topic)) || ('섹션 ' + (secIdx + 1));
    const anchor = (sec && (sec.summary_anchor || sec.summary)) || '';
    const qList = Array.isArray(sec && sec.questions) ? sec.questions : [];

    const normalizedQuestions = qList
      .map(function(q) {
        if (typeof q === 'string') {
          return {
            section_title: title,
            category: '적용',
            explanation: '',
            question: q,
            scripture_anchor: ''
          };
        }
        return {
          section_title: title,
          category: (q && (q.category || q.type)) || '적용',
          explanation: (q && (q.explanation || q.context)) || '',
          question: (q && (q.question || q.text || q.content)) || '',
          scripture_anchor: (q && (q.scripture_anchor || q.anchor)) || ''
        };
      })
      .filter(function(q){ return q.question; });

    return {
      section_title: title,
      summary_anchor: anchor,
      questions: normalizedQuestions
    };
  })
  .filter(function(sec){ return sec.questions.length > 0; });

if (!normalizedSections.length) {
  throw new Error('유효한 sections/questions가 없습니다. 받은 키: ' + Object.keys(parsed).join(', '));
}

const flattened = normalizedSections.reduce(function(acc, sec){ return acc.concat(sec.questions); }, []);
const questions = {
  sections: normalizedSections,
  flat: flattened,
  meta: (qRoot && qRoot.meta) || {}
};

const id = $('처리 대상 선택').first().json.id;

return [{
  json: {
    id: id,
    sermon_summary: sermon_summary,
    questions: questions
  }
}];

const rows = $input.all().map(i => i.json || {});
const now = Date.now();
const STALE_MIN = 10;
const staleMs = STALE_MIN * 60 * 1000;

const isPending = (r) => r?.status === 'pending';
const isStaleProcessing = (r) => {
  if (r?.status !== 'processing') return false;
  const t = r?.updated_at || r?.created_at;
  if (!t) return true;
  const ts = new Date(t).getTime();
  if (Number.isNaN(ts)) return true;
  return (now - ts) >= staleMs;
};

const pending = rows
  .filter(isPending)
  .sort((a,b)=> new Date(a.created_at||0)-new Date(b.created_at||0));

const staleProcessing = rows
  .filter(isStaleProcessing)
  .sort((a,b)=> new Date(a.updated_at||a.created_at||0)-new Date(b.updated_at||b.created_at||0));

const target = pending[0] || staleProcessing[0];

if (!target) return [];

return [{ json: target }];
